    <div class="card-body"><p class="resource-type">学习资料 &middot; RESOURCE</p><h3 class="card-title" :title="resource.title">{{ resource.title }}</h3><p v-if="resource.description" class="card-desc">{{ truncate(resource.description, 58) }}</p><div class="card-footer"><div class="card-stats" aria-label="资源数据"><span><n-icon><EyeOutline /></n-icon>{{ resource.viewCount || 0 }}</span><span><n-icon><DownloadOutline /></n-icon>{{ resource.downloadCount || 0 }}</span></div><span class="detail-arrow" aria-hidden="true">&nearr;</span></div><div v-if="resource.tags && resource.tags.length" class="card-tags"><span v-for="tag in resource.tags.slice(0, 3)" :key="tag.id">{{ tag.name }}</span></div></div>
  </router-link>
</template>
<script setup>
